import{_ as e,c as r,o,a5 as a,aI as n,aJ as i,aK as s,aL as h,aM as c,aN as u}from"./chunks/framework.CVIjMMbU.js";const b=JSON.parse('{"title":"Customizing Marked Structures","description":"","frontmatter":{"title":"Customizing Marked Structures"},"headers":[],"relativePath":"blog/mokeshalong-kuaijiejian.md","filePath":"blog/mokeshalong-kuaijiejian.md","lastUpdated":1778655337000}'),l={name:"blog/mokeshalong-kuaijiejian.md"};function d(g,t,m,p,f,k){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="tutorial-for-customizing-keyboard-shortcuts-for-marked-structures" tabindex="-1">Tutorial for Customizing Keyboard Shortcuts for Marked Structures <a class="header-anchor" href="#tutorial-for-customizing-keyboard-shortcuts-for-marked-structures" aria-label="Permalink to “Tutorial for Customizing Keyboard Shortcuts for Marked Structures”">​</a></h1><p>This tutorial is based on a Mogan Salon presentation and explains how to customize keyboard shortcuts for marked structures. Note that the same shortcut may produce different effects in different modes. There are currently two configuration methods:</p><h2 id="_1-configure-shortcuts-through-the-menu-bar" tabindex="-1">1. Configure Shortcuts Through the Menu Bar <a class="header-anchor" href="#_1-configure-shortcuts-through-the-menu-bar" aria-label="Permalink to “1. Configure Shortcuts Through the Menu Bar”">​</a></h2><ol><li><strong>Insert a marked structure</strong>: Click [Insert] and insert the marked structure for which you want to define a shortcut.</li><li><strong>Open shortcut settings</strong>: Click [Marked Preferences] in the menu bar (wrench icon), then select [New Shortcut].</li><li><strong>Set the shortcut</strong>: Enter your custom shortcut in the shortcut input area, click [Add], and then click [Exit] when finished.</li></ol><h2 id="_2-configure-shortcuts-through-the-tools-menu" tabindex="-1">2. Configure Shortcuts Through the Tools Menu <a class="header-anchor" href="#_2-configure-shortcuts-through-the-tools-menu" aria-label="Permalink to “2. Configure Shortcuts Through the Tools Menu”">​</a></h2><p>In [Tools] -&gt; [Keyboard] -&gt; [Edit Keyboard Shortcuts], enter commands in the <code>(make &#39;corresponding-marked-code)</code> format to configure them. For example, if you want to assign a shortcut to the highlight marker, enter <code>(make &#39;marked)</code>.</p><h2 id="example-configuring-a-highlight-shortcut-through-the-menu-bar" tabindex="-1">[Example] Configuring a [Highlight] Shortcut Through the Menu Bar <a class="header-anchor" href="#example-configuring-a-highlight-shortcut-through-the-menu-bar" aria-label="Permalink to “[Example] Configuring a [Highlight] Shortcut Through the Menu Bar”">​</a></h2><p>The following example uses [Highlight] in semantic markers to illustrate the menu-bar configuration process.</p><ol><li><strong>Insert a marked structure</strong>: Click [Insert] -&gt; [Semantic Markers] -&gt; [Highlight] to insert the marked structure for which you want to define a shortcut.</li></ol><p><img src="'+n+'" alt="Insert the marked structure you want to assign a shortcut to"></p><ol><li><strong>Open shortcut settings</strong>: Click [Marked Preferences] in the menu bar (wrench icon), then select [New Shortcut].</li></ol><p><img src="'+i+'" alt="Click the wrench icon"></p><ol start="3"><li><strong>Set the shortcut</strong>: Enter your custom shortcut in the shortcut input area, such as <code>Ctrl+B</code>, click [Add], and then click [Exit] when finished.</li></ol><p><img src="'+s+'" alt="Enter a custom shortcut"></p><ol start="4"><li><strong>Apply the shortcut</strong>: Select the target text and press the assigned shortcut to highlight the text.</li></ol><p><img src="'+h+'" alt="Shortcut takes effect"> If you want to learn more about the underlying technical principles and additional use cases, you can watch the related Mogan Salon video: <a href="https://www.bilibili.com/video/BV122EGz5Ej4/" target="_blank" rel="noreferrer">Mogan Community Salon: Tutorial on Custom Shortcuts and Macro Definitions</a>. The video provides a more comprehensive and in-depth explanation of the relevant techniques, helping you master and apply custom keyboard shortcuts for marked structures more efficiently.</p><p>You can scan the QR codes below to join the Mogan Community QQ group and Discord channel and participate in future salons.</p><h3 id="qq-group" tabindex="-1"><strong>QQ Group</strong> <a class="header-anchor" href="#qq-group" aria-label="Permalink to “QQ Group”">​</a></h3><p><img src="'+c+'" alt="QQ group"></p><h3 id="discord-channel" tabindex="-1"><strong>Discord Channel</strong> <a class="header-anchor" href="#discord-channel" aria-label="Permalink to “Discord Channel”">​</a></h3><p><img src="'+u+'" alt="Discord QR code"></p>',21)])])}const S=e(l,[["render",d]]);export{b as __pageData,S as default};
